#include<bits/stdc++.h>
using namespace std;
int n,m,ans;
bool vis[11][11];
int dx[4]={0,1,0,-1};
int dy[4]={1,0,-1,0};
void dfs(int x,int y)
{
    if(x==0||y==0||x==n||y==m)
    {
        ans++;
        return;
    }
    for(int i=0;i<4;i++)
    {
        int xx=x+dx[i];
        int yy=y+dy[i];
        if(!vis[xx][yy])
        {
            vis[xx][yy]=1;
            dfs(xx,yy);
            vis[xx][yy]=0;
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++)
    {
        vis[i][1]=vis[i][0]=1;
        dfs(i,1);
        vis[i][1]=vis[i][0]=0;
    }
    for(int i=1;i<m;i++)
    {
        vis[1][i]=vis[0][i]=1;
        dfs(1,i);
        vis[1][i]=vis[0][i]=0;
    }
    printf("%d",ans);
    return 0;
}
